## 1️⃣ `pcapng.mli` – public OCaml interface

```ocaml
(* ----------------------------------------------------------------------
   OCaml bindings for libpcapng (iterator over frames)
   ---------------------------------------------------------------------- *)

(** An opaque iterator over the frames of a pcapng file.  The iterator is
    allocated in C++ and will be automatically freed when the OCaml value
    becomes unreachable (or when {!close} is called explicitly). *)
type iterator

(** A single captured frame.  All fields are copied from the C++ side,
    the payload is a fresh OCaml [bytes] buffer (no zero‑copy in this
    version – see the comment at the bottom of the stub for a zero‑copy
    alternative). *)
type frame = {
  ts     : int64;                     (** capture timestamp, nanoseconds *)
  caplen : int;                       (** number of bytes actually captured *)
  len    : int;                       (** original length of the packet on the wire *)
  data   : bytes;                     (** captured payload (size = caplen) *)
}

(** Raised when the underlying pcapng file cannot be opened or when the
    file is malformed.  The string contains the libpcapng error message. *)
exception Parse_error of string

(** Open a pcapng file and obtain an iterator.  The iterator can be
    reused as many times as you like; the underlying C++ object will keep
    its own internal cursor. *)
val open_file : string -> iterator

(** Explicitly close an iterator.  This is optional – the iterator will be
    closed automatically by the finaliser, but calling it early can be
    useful to release the underlying file descriptor sooner. *)
val close : iterator -> unit

(** Walk the whole collection, calling [cb] on each frame.  The callback
    receives a fresh {!frame} record.  If the callback raises an exception
    the iteration stops and the exception is propagated to the caller. *)
val iter : iterator -> (frame -> unit) -> unit

(** A lower‑level version that avoids building the OCaml record: the
    callback receives the four fields directly.  This version is a tiny
    bit faster (no allocation of the record) and is the one that the C
    stub actually uses internally.  It is exposed for benchmarking or
    for users that want to avoid the extra allocation. *)
val iter_raw :
  iterator ->
  (int64 -> int -> int -> bytes -> unit)   (* ts caplen len data *)
  -> unit
```

