## 3️⃣ Build instructions (Makefile snippet)

```make
# --------------------------------------------------------------
# Minimal Makefile to build the binding.
# --------------------------------------------------------------

OCAMLFLAGS = -thread -I +camlp4
CXXFLAGS   = -O3 -Wall -fPIC -std=c++17 $(shell ocamlc -config | awk '/cflags:/ {print $$2}')
LDFLAGS    = -shared

# Adjust these includes / libs to match your libpcapng installation
PCAPNG_INC = -I/usr/include/libpcapng
PCAPNG_LIB = -lpcapng

all: libpcapng_stubs.so pcapng.cma

# The shared library that OCaml will link with
libpcapng_stubs.so: pcapng_stubs.cpp
	$(CXX) $(CXXFLAGS) $(PCAPNG_INC) -c $< -o $@.o
	$(CXX) $(LDFLAGS) -o $@ $@.o $(PCAPNG_LIB)

# Compile the .mli (optional, just for completeness)
pcapng.cmi: pcapng.mli
	ocamlc -c $<

# Build a stub library that OCaml can link with (static for simplicity)
pcapng.cma: pcapng.cmi libpcapng_stubs.so
	ocamlc -a -o $@ -cclib -lpcapng_stubs $<

clean:
	rm -f *.o *.so *.cmi *.cma
```

> **Note** – The Makefile assumes that the libpcapng headers are installed under
> `/usr/include/libpcapng` and that the library can be linked with `-lpcapng`.  
> Adjust `PCAPNG_INC` and `PCAPNG_LIB` to match your environment.

